315→// ── Suite 4: resolveDownloadToken ─────────────────────────────────────────────
316→
317→describe('resolveDownloadToken', () => {
318→  beforeEach(() => {
319→    vi.stubEnv('EXPORT_ALLOW_ANY_TENANT', 'true');
320→    vi.mocked(buildWorkbookFile).mockResolvedValue(undefined);
321→  });
322→
323→  afterEach(() => {
324→    vi.unstubAllEnvs();
325→  });
326→
327→  it('returns job and filePath for a valid token', async () => {
328→    const { job } = await createExcelExportJob(
